#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    //SHADER MILKDROP2077+AI

    vec3 col = vec3(0,0,0);
    vUv = (vUvOriginal - 0.5) * uAspect.xy;

    const float FAR = 80.0;
    const int count = 80;
    const float T = uTime * 0.25;
    const float PI = 3.14159265359;
    const float TWO_PI = 6.28318530718;

    for(int i = 0; i < count; i++) {
        float v = float(i+1)/float(count);
        float fi = float(i);

        // Optimized random number generation
        float rnd = fract(fi/30.0 + (0.5+v*TWO_PI)*PI);
        float rnd2 = fract(rnd*100.0);
        float rnd3 = fract(rnd+rnd2);

        // Precompute common terms
        float angle1 = rnd*TWO_PI + v;
        float angle2 = rnd2*TWO_PI - v;
        float rnd_sum = rnd + rnd2;

        // Star position calculations (optimized trig)
        float x = cos(angle1) * (rnd + 1.0) * PI;
        float y = sin(angle2) * (rnd2 + rnd + 1.0) * PI;
        float z = fract(-T*(rnd_sum*0.5)*PI*(0.5+v)) * (0.001+v)*FAR;

        // Star rendering
        float z_inv = 1.0/z;  // Reciprocal for faster division
        vec2 starPos = vec2(x,y) * z_inv;
        float dist_sq = dot(vUv-starPos, vUv-starPos);  // Avoid sqrt with distance squared
        float s = clamp(mix(0.001, 0.009, rnd2) * inversesqrt(max(1e-8, dist_sq)), 0.0, 1.0);
        s *= smoothstep(v, 0.25, abs(z*0.0125));  // 1/FAR = 0.0125

        // Color accumulation (optimized)
        col += s * vec3(rnd, rnd2, rnd3);
    }

    ret = vec4(col, 1.0);

  fragColor = ret;
}

